form:Form.form:Scripts:
		function CALL_MODE(mode)
{                                                          
	var MyITEM;
	var MyGROUP;
	var MyOBJ;

	MyITEM =GROUP_TREE.GetItem(Ctrl("TREE_ID").GetXValue());
	MyGROUP=GROUP_TREE.GetGroup(Ctrl("TREE_ID").GetXValue());

	MyOBJ=(MyITEM?MyITEM:MyGROUP);

	var MyRetVal=new ObjtectGroupResult();

	//Obtengo el ID Previo
	MyRetVal.PrevID=Ctrl("TREE_ID").GetXValue().split("/");
	if (MyRetVal.PrevID.length>1) MyRetVal.PrevID.length--;
	MyRetVal.PrevID=MyRetVal.PrevID.join("/");

	if (MyOBJ)
	{         
		var subtag=MyOBJ.Tag.split("&")[0];
		switch (subtag)
		{ 
			case "proyecto-root":
			case "proyecto-child":
				if (mode=="HORAS")
				  {
				    alert("Lo siento mucho...\r\nNo esta Implementado!")
				  } else
				  	{
							if (mode=="ADD") MyRetVal.PrevID=MyOBJ.FullId;
							openNewFlow("NucleusProject.Base.Project.Proyectos.MAIN.flow",mode,'<DATA id="'+MyOBJ.Id+'" />',MyRetVal,"L");
						}
			break;    

			case "root":
			case "template":
				if (mode=="HORAS")
				  {
				    alert("Lo siento mucho...\r\nNo esta Implementado!")
				  } else
				  	{
							openNewFlow("NucleusProject.Base.Project.Proyectos.MAIN.flow",mode,'<DATA id="" />',MyRetVal,"L");
						}
			break;

			case "tarea-group":                        
				if (mode=="HORAS")
				  {
				    alert("Lo siento mucho...\r\nNo esta Implementado!")
				  } else
				  	{
 							MyRetVal.PrevID=MyOBJ.FullId;
							openNewFlow("NucleusProject.Base.Project.Tareas.MAIN.flow",mode,'<DATA id="'+MyOBJ.Id.substr(2)+'" />',MyRetVal,"L");
						}
			break;    

			case "tarea":
				if ((mode=="ADD") || (mode=="COPY"))
				{
					MyID=MyRetVal.PrevID.split("/");
					MyID=MyID[MyID.length-1];
					MyID=MyID.substr(2);
					MyID=MyOBJ.Id;
					openNewFlow("NucleusProject.Base.Project.Tareas.MAIN.flow",mode,'<DATA id="'+MyID+'" />',MyRetVal,"L");							
				} else
				  if (mode=="HORAS")
				  {

					MyID=MyRetVal.PrevID.split("/");
					MyID=MyID[MyID.length-1];
					MyID=MyID.substr(2);
					MyID=MyOBJ.Id;
				  //alert(MyID);
				  openNewFlow("NucleusProject.Base.Project.Trabajos.trab_flow","initialize",'<DATA oi_tarea="'+MyID+'" />',MyRetVal,"L");
				  } else
				  	{
							MyID=MyRetVal.PrevID.split("/");
							MyID=MyID[MyID.length-1];
							MyID=MyID.substr(2);
					   	MyID=MyOBJ.Id;
					   	//alert(MyID);
					   	//alert(MyRetVal);
					   	openNewFlow("NucleusProject.Base.Project.Tareas.MAIN.flow",mode,'<DATA id="'+MyID+'" />',MyRetVal,"L");							
					  }

			break;       

			default:
				alert("Lo siento mucho...\r\nNo esta Implementado!")
			break;
		}
	}
}    
function HORAS()
{  
	CALL_MODE("HORAS");
}
